+    let thread_ts = event
+        .get("thread_ts")
+        .and_then(Value::as_str)
+        .or_else(|| {
+            event
+                .get("message")
+                .and_then(|message| message.get("thread_ts"))
+                .and_then(Value::as_str)
+        })
+        .or_else(|| {
+            event
+                .get("previous_message")
+                .and_then(|message| message.get("thread_ts"))
+                .and_then(Value::as_str)
+        })?;
+
+    Some(ThreadInfo::from_slack_thread(thread_ts, None))
+}
